1370: /** ZSTD_dictAndWindowLog() :
1371:  * Returns an adjusted window log that is large enough to fit the source and the dictionary.
1372:  * The zstd format says that the entire dictionary is valid if one byte of the dictionary
1373:  * is within the window. So the hashLog and chainLog should be large enough to reference both
1374:  * the dictionary and the window. So we must use this adjusted dictAndWindowLog when downsizing
1375:  * the hashLog and windowLog.
1376:  * NOTE: srcSize must not be ZSTD_CONTENTSIZE_UNKNOWN.
1377:  */
1378: static U32 ZSTD_dictAndWindowLog(U32 windowLog, U64 srcSize, U64 dictSize)
1379: {
1380:     const U64 maxWindowSize = 1ULL << ZSTD_WINDOWLOG_MAX;
1381:     /* No dictionary ==> No change */
1382:     if (dictSize == 0) {
1383:         return windowLog;
1384:     }
1385:     assert(windowLog <= ZSTD_WINDOWLOG_MAX);
1386:     assert(srcSize != ZSTD_CONTENTSIZE_UNKNOWN); /* Handled in ZSTD_adjustCParams_internal() */
1387:     {
1388:         U64 const windowSize = 1ULL << windowLog;
1389:         U64 const dictAndWindowSize = dictSize + windowSize;
1390:         /* If the window size is already large enough to fit both the source and the dictionary
1391:          * then just use the window size. Otherwise adjust so that it fits the dictionary and
1392:          * the window.
1393:          */
1394:         if (windowSize >= dictSize + srcSize) {
1395:             return windowLog; /* Window size large enough already */
1396:         } else if (dictAndWindowSize >= maxWindowSize) {
1397:             return ZSTD_WINDOWLOG_MAX; /* Larger than max window log */
1398:         } else  {
1399:             return ZSTD_highbit32((U32)dictAndWindowSize - 1) + 1;
1400:         }
1401:     }
1402: }
